from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about an athlete into a fluent, combined sentence."""
    if not triples:
        return ""

    from collections import defaultdict
    import datetime

    # Group triples by subject
    subj_map = defaultdict(list)
    for t in triples:
        subj_map[t.subject].append((t.predicate, t.object))

    def human_date(date_str: str) -> str:
        """Convert YYYY-MM-DD to a readable format if possible."""
        try:
            d = datetime.datetime.strptime(date_str, "%Y-%m-%d")
            return d.strftime("%B %-d, %Y")
        except Exception:
            return date_str

    def join_items(items):
        """Join a list of strings with commas and 'and'."""
        if not items:
            return ""
        if len(items) == 1:
            return items[0]
        return ", ".join(items[:-1]) + " and " + items[-1]

    sentences = []

    for subj, props in subj_map.items():
        # Separate predicates into categories
        birth_info = []
        physical = []
        career = []
        draft = []
        education = []
        other = []

        for p, o in props:
            if p in ("birthDate", "birthYear", "birthPlace"):
                birth_info.append((p, o))
            elif p in ("height", "weight"):
                physical.append((p, o))
            elif p in ("club", "currentteam", "currentclub", "formerTeam", "position", "league", "manager", "ground"):
                career.append((p, o))
            elif p in ("draftYear", "draftRound", "draftPick", "draftTeam"):
                draft.append((p, o))
            elif p in ("college", "youthclub"):
                education.append((p, o))
            else:
                other.append((p, o))

        parts = []

        # Birth information
        if birth_info:
            date_part = ""
            place_part = ""
            for p, o in birth_info:
                if p == "birthDate":
                    date_part = f"born on {human_date(o)}"
                elif p == "birthYear":
                    date_part = f"born in {o}"
                elif p == "birthPlace":
                    place_part = f"in {o}"
            if date_part and place_part:
                parts.append(f"{subj} was {date_part} {place_part}")
            elif date_part:
                parts.append(f"{subj} was {date_part}")
            elif place_part:
                parts.append(f"{subj} was born {place_part}")

        # Physical attributes
        if physical:
            phys_parts = []
            for p, o in physical:
                if p == "height":
                    phys_parts.append(f"{o} metres tall")
                elif p == "weight":
                    phys_parts.append(f"weighs {o}")
            if phys_parts:
                parts.append(f"{subj} is " + " and ".join(phys_parts))

        # Education
        if education:
            edu_parts = []
            for p, o in education:
                if p == "college":
                    edu_parts.append(f"attended {o}")
                elif p == "youthclub":
                    edu_parts.append(f"started at youth club {o}")
            if edu_parts:
                parts.append(f"{subj} " + " and ".join(edu_parts))

        # Draft info
        if draft:
            draft_parts = []
            for p, o in draft:
                if p == "draftYear":
                    draft_parts.append(f"drafted in {o}")
                elif p == "draftRound":
                    draft_parts.append(f"selected in round {o}")
                elif p == "draftPick":
                    draft_parts.append(f"the {o}th pick")
                elif p == "draftTeam":
                    draft_parts.append(f"by {o}")
            if draft_parts:
                parts.append(f"{subj} was " + " and ".join(draft_parts))

        # Career information
        if career:
            clubs = []
            former = []
            positions = []
            leagues = []
            managers = []
            grounds = []
            for p, o in career:
                if p in ("club", "currentteam", "currentclub"):
                    clubs.append(o)
                elif p == "formerTeam":
                    former.append(o)
                elif p == "position":
                    positions.append(o)
                elif p == "league":
                    leagues.append(o)
                elif p == "manager":
                    managers.append(o)
                elif p == "ground":
                    grounds.append(o)
            if clubs:
                parts.append(f"{subj} plays for {join_items(clubs)}")
            if former:
                parts.append(f"{subj} formerly played for {join_items(former)}")
            if positions:
                parts.append(f"{subj} plays as a {join_items(positions)}")
            if leagues:
                parts.append(f"{subj} competes in the {join_items(leagues)} league")
            if managers:
                parts.append(f"{subj} is managed by {join_items(managers)}")
            if grounds:
                parts.append(f"{subj}'s home ground is {join_items(grounds)}")

        # Other predicates
        for p, o in other:
            parts.append(f"{subj} {p} {o}")

        # Combine parts for this subject
        sentence = "; ".join(parts)
        if not sentence.endswith('.'):
            sentence = sentence + "."
        sentences.append(sentence)

    # Join different subject sentences with a space
    return " ".join(sentences)

# EVOLVE-BLOCK-END

